Files:
- platform/browser-extension/src/side-panel/components/ConfigDialog.stories.tsx

Context:
The existing stories (ConfigDialog.stories.tsx) use a Wrapper component that renders ConfigDialog with controlled open state:
```tsx
const Wrapper = ({
  schema,
  resolved,
  displayName = 'SQLPad',
}: {
  schema: ConfigSchema;
  resolved?: Record<string, unknown>;
  displayName?: string;
}) => {
  const [open, setOpen] = useState(true);
  return (
    <div className="w-80">
      <Button size="sm" onClick={() => setOpen(true)}>Open Settings</Button>
      <ConfigDialog
        open={open}
        onOpenChange={setOpen}
        pluginName="sqlpad"
        displayName={displayName}
        configSchema={schema}
        resolvedSettings={resolved}
      />
    </div>
  );
};
```

The url schema for stories:
```ts
const urlSchema: ConfigSchema = {
  instanceUrl: {
    type: 'url',
    label: 'Instance URL',
    description: 'The URL of your self-hosted instance',
    required: true,
    placeholder: 'https://sqlpad.example.com',
  },
};
```

The existing `PreFilledValues` story already uses the multi-instance map format:
```ts
resolved={{ instanceUrl: { production: 'https://sqlpad.mycompany.com', staging: 'https://sqlpad.staging.mycompany.com' } }}
```

But it's mixed with other field types and not focused on the multi-instance UI.

New stories to add:

1. **SingleInstance** — url field with one pre-filled entry:
```tsx
const SingleInstance: Story = {
  render: () => (
    <Wrapper
      schema={urlSchema}
      resolved={{ instanceUrl: { production: 'https://sqlpad.mycompany.com' } }}
      displayName="Single Instance"
    />
  ),
};
```

2. **MultipleInstances** — url field with 3 pre-filled entries:
```tsx
const MultipleInstances: Story = {
  render: () => (
    <Wrapper
      schema={urlSchema}
      resolved={{ instanceUrl: {
        production: 'https://sqlpad.prod.example.com',
        staging: 'https://sqlpad.staging.example.com',
        development: 'https://sqlpad.dev.example.com',
      }}}
      displayName="Multiple Instances"
    />
  ),
};
```

3. **EmptyUrlField** — url field with no pre-filled values (initial setup):
```tsx
const EmptyUrlField: Story = {
  render: () => <Wrapper schema={urlSchema} displayName="Empty URL Field" />,
};
```

4. **UrlFieldOptional** — optional url field (no * marker, all rows removable):
```tsx
const optionalUrlSchema: ConfigSchema = {
  instanceUrl: {
    type: 'url',
    label: 'Instance URL',
    description: 'Optional self-hosted instance URL',
    required: false,
    placeholder: 'https://sqlpad.example.com',
  },
};
const UrlFieldOptional: Story = {
  render: () => (
    <Wrapper
      schema={optionalUrlSchema}
      resolved={{ instanceUrl: { production: 'https://sqlpad.mycompany.com' } }}
      displayName="Optional URL"
    />
  ),
};
```

5. **MultiInstanceThemePair** — ThemeGrid showing multi-instance in both themes:
```tsx
const MultiInstanceThemePair: Story = {
  render: () => (
    <ThemeGrid>
      <Wrapper
        schema={urlSchema}
        resolved={{ instanceUrl: {
          production: 'https://sqlpad.prod.example.com',
          staging: 'https://sqlpad.staging.example.com',
        }}}
        displayName="Theme Demo"
      />
    </ThemeGrid>
  ),
};
```

6. **UrlFieldMixedWithOtherFields** — url field alongside string, number, boolean, select fields to show how multi-instance integrates with the rest of the form:
```tsx
const mixedSchema: ConfigSchema = {
  instanceUrl: { type: 'url', label: 'Instance URL', required: true, placeholder: 'https://sqlpad.example.com' },
  apiToken: { type: 'string', label: 'API Token', required: false, placeholder: 'sk-...' },
  verbose: { type: 'boolean', label: 'Verbose Logging', required: false },
};
const UrlFieldMixedWithOtherFields: Story = {
  render: () => (
    <Wrapper
      schema={mixedSchema}
      resolved={{
        instanceUrl: { production: 'https://sqlpad.prod.example.com', staging: 'https://sqlpad.staging.example.com' },
        apiToken: 'sk-abc123',
        verbose: true,
      }}
      displayName="Mixed Fields"
    />
  ),
};
```

Add all stories to the export block at the bottom of the file:
```ts
export {
  UrlField,
  StringField,
  NumberField,
  BooleanField,
  SelectField,
  PreFilledValues,
  AllFieldTypes,
  AllFieldTypesThemePair,
  // New multi-instance stories
  SingleInstance,
  MultipleInstances,
  EmptyUrlField,
  UrlFieldOptional,
  MultiInstanceThemePair,
  UrlFieldMixedWithOtherFields,
};
```

Constraints:
- Do NOT modify the ConfigDialog component — only add stories
- Do NOT create a separate story file — add to the existing ConfigDialog.stories.tsx
- Use the existing Wrapper and ThemeGrid helpers
- Ensure all stories render the dialog in the open state (Wrapper's default)
- Use realistic but non-personal data (example.com, mycompany.com domains)
